import{u as e}from"./index.95f2040e.js";import{_ as a,c as i,o as n,f as t}from"./entry.79f37cee.js";import"./vue.f36acd1f.494dcfe6.js";const s=""+new URL("inqa-badge.c4998805.jpg",import.meta.url).href,r=""+new URL("inqa-vorgehen.56ef5190.jpg",import.meta.url).href;const d=t('<div class="row" data-v-811b826c><div class="col-xs-12 col-lg-offset-1 col-lg-10 col-md-12" data-v-811b826c><h1 data-v-811b826c> INQA-Coaching in Hamburg </h1><h3 class="z-100" data-v-811b826c>Agil in die digitale Zukunft mit dem INQA-Förderprogramm für KMU</h3></div></div><div class="row" data-v-811b826c><div class="col-xs-12 col-md-8 col-lg-offset-1 col-lg-7" data-v-811b826c><p class="z-100" data-v-811b826c> Die Initiative Neue Qualität der Arbeit (INQA) ist ein Bundesprogramm für die Förderung kleiner und mittlerer Unternehmen sowie von Non-Profit-Organisationen. Beim INQA Coaching geht es darum, Unternehmen rund um das Thema Digitalisierung durch eine externe Prozessbegleitung zu unterstützen. Dabei wird auf Agilität und die Partizipation von Mitarbeitenden gesetzt. </p><p class="z-100" data-v-811b826c> Ich bin autorisierte und geprüfte INQA-Coach und begleite Unternehmen in und um Hamburg in Veränderungsprozessen. Die Förderung umfasst maximal 12 Beratungstage. Bis zu 80 Prozent meiner Beratungskosten können durch das Programm finanziert werden. </p></div><div class="col-xs-7 col-xs-offset-2 col-md-offset-0 col-md-4 col-lg-3" data-v-811b826c><img src="'+s+'" alt="INQA Badge" class="responsive-img" data-v-811b826c></div></div><div class="row" data-v-811b826c><div class="col-xs-12 col-md-12 col-lg-offset-1 col-lg-10" data-v-811b826c><h3 data-v-811b826c>Welche Vorteile bietet INQA-Coaching?</h3><p class="z-100" data-v-811b826c> INQA-Coaching bedient sich agiler Methoden und befähigt Unternehmen zum eigenständigen agilen Arbeiten. Gleichzeitig bezieht das Programm durchgehend Mitarbeitende ein, das heißt, die Beschäftigten werden bei allen Schritten konsequent beteiligt. So entstehen passgenaue und nachhaltige Lösungen für Ihr Unternehmen, die breit getragen werden und auch nach dem Ende des INQA-Coachings Bestand haben. </p><h3 data-v-811b826c>Wer wird gefördert?</h3><p class="z-100" data-v-811b826c>Das Förderprogramm richtet sich an in Deutschland ansässige KMU, die seit mindestens zwei Jahren am Markt sind, weniger als 250 Mitarbeitende beschäftigen und dabei mindestens eine Vollzeitkraft sozialversicherungspflichtig anstellen. Die Unternehmen sollten einen Jahresumsatz unter 50 Millionen Euro oder eine Bilanzsumme unter 43 Millionen Euro vorweisen und in den vergangenen drei Steuerjahren nicht mehr als 200.000 Euro an staatlichen Beihilfen, inklusive der INQA-Coaching-Förderung, erhalten haben.</p></div></div><div class="row" data-v-811b826c><div class="col-xs-12 col-md-12 col-lg-offset-1 col-lg-10" data-v-811b826c><h3 data-v-811b826c>Was sind die Förderschwerpunkte?</h3><p class="z-100" data-v-811b826c>Das INQA-Programm definiert einige große betriebliche Gestaltungsfelder. Ich unterstütze Unternehmen als autorisierte INQA-Coach in folgenden Bereichen: </p><ul class="z-100" data-v-811b826c><li data-v-811b826c>Führung, berufliche Entwicklung &amp; Karriere</li><li data-v-811b826c>Arbeitsplatz der Zukunft, Arbeitszeit &amp; Leistungspolitik</li><li data-v-811b826c>Soziale Beziehungen &amp; Kultur</li><li data-v-811b826c>Produktionsmodell &amp; Arbeitsorganisation</li><li data-v-811b826c>Neue Geschäftsmodelle &amp; Innovationsstrategien</li></ul><h3 data-v-811b826c>Wie läuft das INQA-Coaching ab?</h3><p class="z-100" data-v-811b826c>Der Ablauf des INQA-Coachings gliedert sich in drei Phasen:</p><ol class="z-100" data-v-811b826c><li data-v-811b826c>Initialphase (Dauer: ca. 1 Monat)</li><li data-v-811b826c>Innovationsphase ( Dauer: 3-4 Monate)</li><li data-v-811b826c>Lernphase (Dauer: 1 Monat)</li></ol><img alt="INQA Vorgehen" class="responsive-img" src="'+r+'" data-v-811b826c><p class="z-100" data-v-811b826c><b data-v-811b826c>Initialphase:</b> In dieser Phase findet die Auftragsklärung statt, das zu bearbeitende Thema wird festgelegt und der Kick-off-Workshop wird durchgeführt. In dieser Phase werden Lab-Team und Lenkungskreis gebildet. </p><p class="z-100" data-v-811b826c><b data-v-811b826c>Innovationsphase:</b> In diesem Abschnitt nimmt das Lab-Team seine Arbeit auf. Dieser Prozess besteht aus drei Phasen, die jeweils etwa vier Wochen dauern. Jeder Abschnitt startet mit einem Planungs-Workshop (ungefähr 4 Stunden) und endet mit einem Auswertungs-Workshop (ungefähr 1,5 Stunden). Die eigentliche Bearbeitung des gewählten Themas verbringt das Lab-Team in der Zeit dazwischen – überwiegend selbstorganisiert. Vorgesehen sind ca. zwei Stunden pro Woche in der Arbeitsphase, die jedes Teammitglied mindestens innerhalb der regulären Arbeitszeit aufwenden sollte, der*die Lab-Team-Verantwortliche mindestens 4 Stunden pro Woche. </p><p class="z-100" data-v-811b826c><b data-v-811b826c>Lernphase:</b> Diese Phase dient dazu, die Erfahrungen und erzielte Ergebnisse zu evaluieren. Dies geschieht im Rahmen eines Evaluations-Workshops. </p><p class="z-100" data-v-811b826c>Weitere Informationen zum Ablauf und den Förderschwerpunkten gibt es im <a href="https://login.inqa.de/fileadmin/PDF/Materialien/230619_Flyer_INQA-Coaching_digitale_bf_Coaches.pdf" data-v-811b826c>offiziellen Flyer</a> und auf der <a href="https://www.inqa.de/DE/handeln/inqa-coaching/uebersicht.html" data-v-811b826c>INQA Website.</a></p><p class="z-100" data-v-811b826c>Du möchtest mehr erfahren? Kontaktiere mich für ein unverbindliches Beratungsgespräch.</p></div></div>',4),c=[d],l={name:"INQA"},o=Object.assign(l,{setup(h){return e({title:"INQA-Coaching",ogTitle:"INQA-Coaching",ogDescription:"Agil in die digitale Zukunft: Jetzt Förderung beantragen für ein INQA Coaching! Das geförderte Beratungsprogramm für KMU.",description:"Agil in die digitale Zukunft: Jetzt Förderung beantragen für ein INQA Coaching! Das geförderte Beratungsprogramm für KMU."}),(g,u)=>(n(),i("div",null,c))}}),p=a(o,[["__scopeId","data-v-811b826c"]]);export{p as default};
